#!/usr/bin/env node
/* sprint3.mjs — applies Sprint 3 (structured intelligence: extractors, events, summary, local LLM). */
import { mkdirSync, writeFileSync } from "node:fs";
import { dirname } from "node:path";
const FILES=[
  ["package.json", ""],
  ["PROJECT_LOG.md", ""],
  ["src/main/services/intelligence/extractors.ts", ""],
  ["src/main/db/intelligence.repo.ts", ""],
  ["src/main/services/ai/ollama.ts", ""],
  ["src/main/services/intelligence/summary.ts", ""],
  ["src/main/services/intelligence/ingest.ts", ""],
  ["src/main/ipc/index.ts", ""],
  ["src/preload/index.ts", ""],
  ["src/preload/index.d.ts", ""],
  ["src/renderer/src/App.tsx", ""],
  ["src/renderer/src/assets/main.css", ""]
];
let n=0; for(const [rel,b64] of FILES){ mkdirSync(dirname(rel),{recursive:true}); writeFileSync(rel,Buffer.from(b64,"base64")); n++; }
console.log(`✅ Sprint 3 applied: ${n} files written/updated.`);
console.log("Next: npm install  &&  npm run dev   (optional: install Ollama + \`ollama pull llama3.2\` for AI summaries)");
